fn main() {
    let mut num = 5;

    // Creating raw pointers is SAFE
    let r1 = &num as *const i32;
    let r2 = &mut num as *mut i32;

    // Dereferencing them is UNSAFE
    unsafe {
        println!("r1 is: {}", *r1);
        println!("r2 is: {}", *r2);

        *r2 = 10;
        println!("r2 is now: {}", *r2);
    }
}
